241: /**
242:  * This is called when the panel changes from another panel
243:  */
244: export const tablePanelChangedHandler = (
245:   panel: PanelModel<Partial<Options>>,
246:   prevPluginId: string,
247:   prevOptions: any
248: ) => {
249:   // Changing from angular table panel
250:   if (prevPluginId === 'table-old' && prevOptions.angular) {
251:     const oldOpts = prevOptions.angular;
252:     const transformations = migrateTransformations(panel, oldOpts);
253:     const prevDefaults = oldOpts.styles.find((style: any) => style.pattern === '/.*/');
254:     const defaults = migrateDefaults(prevDefaults);
255:     const overrides = oldOpts.styles.filter((style: any) => style.pattern !== '/.*/').map(migrateTableStyleToOverride);
256: 
257:     panel.transformations = transformations;
258:     panel.fieldConfig = {
259:       defaults,
260:       overrides,
261:     };
262:   }
263: 
264:   return {};
265: };
